// ── Validation & Anti-spam ──────────────────────────────
const body = $input.first().json.body || $input.first().json;

const { name, email, phone, company, message, source, honeypot } = body;

// 1. Champs requis
const required = { name, email, phone, message };
for (const [field, value] of Object.entries(required)) {
  if (!value || String(value).trim() === '') {
    throw new Error(`Champ manquant : ${field}`);
  }
}

// 2. Format email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  throw new Error('Format email invalide');
}

// 3. Honeypot anti-spam (champ caché rempli = bot)
if (honeypot && honeypot.trim() !== '') {
  throw new Error('Spam détecté — honeypot rempli');
}

// 4. Longueur message minimum
if (message.trim().length < 10) {
  throw new Error('Message trop court');
}

// 5. Output structuré
return [{
  json: {
    name: name.trim(),
    email: email.trim().toLowerCase(),
    phone: phone ? phone.trim() : '',
    company: company ? company.trim() : 'Non renseigné',
    message: message.trim(),
    source: source || 'website',
    timestamp: new Date().toISOString(),
    prenom: name.trim().split(' ')[0]
  }
}];

