=Analyse ce lead et retourne exactement ce JSON (rien d'autre) :

{
  "score": "Hot" | "Warm" | "Cold",
  "raison": "string (max 2 phrases, en français)",
  "intent_signals": ["signal1", "signal2"],
  "action": "string (prochaine étape recommandée)",
  "urgence": "high" | "medium" | "low"
}

Critères :
- Hot  = intention d'achat claire + entreprise identifiable + urgence exprimée
- Warm = intérêt réel mais urgence absente ou information incomplète
- Cold = curieux, étudiant, concurrent, message vague ou hors cible

Nom         : {{ $node['Validation & Anti-spam'].json.name }}
Email       : {{ $node['Validation & Anti-spam'].json.email }}
Téléphone   : {{ $node['Validation & Anti-spam'].json.phone }}
Entreprise  : {{ $node['Validation & Anti-spam'].json.company }}
Message     : {{ $node['Validation & Anti-spam'].json.message }}
Source      : {{ $node['Validation & Anti-spam'].json.source }}
Date        : {{ $node['Validation & Anti-spam'].json.timestamp }}

parameters.jsCode:
// ── Parse réponse Claude ──────────────────────────────
const lead = $node['Validation & Anti-spam'].json;
let scoring;

try {
  const content = $input.first().json.content[0].text;
  // Extraire le JSON même s'il y a du texte autour
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('Pas de JSON dans la réponse');
  scoring = JSON.parse(jsonMatch[0]);

  // Valider les champs attendus
  if (!['Hot', 'Warm', 'Cold'].includes(scoring.score)) {
    throw new Error('Score invalide');
  }
} catch (e) {
  // Fallback : score Warm + flag manuel
  scoring = {
    score: 'Warm',
    raison: 'Score automatique indisponible — revue manuelle requise.',
    intent_signals: [],
    action: 'Vérifier manuellement ce lead',
    urgence: 'medium',
    fallback: true
  };
}

return [{
  json: {
    ...lead,
    score: scoring.score,
    raison: scoring.raison,
    intent_signals: (scoring.intent_signals || []).join(', '),
    action: scoring.action,
    urgence: scoring.urgence,
    scoring_fallback: scoring.fallback || false
  }
}];

